#!/usr/bin/env python3
"""TASK-5: Add itertools and extend hubbard_u_sweep_slurm with product/pairwise sweep modes"""
import base64, json, subprocess, sys
from pathlib import Path

TASK_ID = "TASK-5"
STEPS = json.loads('[{"before_b64": "", "after_b64": "", "target": "/Users/tony/programming/castep_workflow_framework/Cargo.toml", "index": 0, "is_create": false}, {"before_b64": "", "after_b64": "", "target": "/Users/tony/programming/castep_workflow_framework/examples/hubbard_u_sweep_slurm/Cargo.toml", "index": 1, "is_create": false}, {"before_b64": "ICAgIC8vLyBDQVNURVAgYmluYXJ5IG5hbWUgb3IgcGF0aCAodXNlZCBpbiAtLWxvY2FsIG1vZGUpCiAgICAjW2FyZyhsb25nLCBkZWZhdWx0X3ZhbHVlID0gImNhc3RlcCIpXQogICAgcHViIGNhc3RlcF9jb21tYW5kOiBTdHJpbmcsCn0=", "after_b64": "", "target": "/Users/tony/programming/castep_workflow_framework/examples/hubbard_u_sweep_slurm/src/config.rs", "index": 2, "is_create": false}, {"before_b64": "", "after_b64": "", "target": "/Users/tony/programming/castep_workflow_framework/examples/hubbard_u_sweep_slurm/src/main.rs", "index": 3, "is_create": false}, {"before_b64": "ICAgIGxldCBtdXQgd29ya2Zsb3cgPSBXb3JrZmxvdzo6bmV3KCJodWJiYXJkX3Vfc3dlZXBfc2x1cm0iKQogICAgICAgIC53aXRoX21heF9wYXJhbGxlbChjb25maWcubWF4X3BhcmFsbGVsKT8KICAgICAgICAud2l0aF9sb2dfZGlyKCJsb2dzIik7", "after_b64": "ICAgIGxldCBtdXQgd29ya2Zsb3cgPSBXb3JrZmxvdzo6bmV3KCJodWJiYXJkX3Vfc3dlZXBfc2x1cm0iKQogICAgICAgIC53aXRoX21heF9wYXJhbGxlbChjb25maWcubWF4X3BhcmFsbGVsKT8KICAgICAgICAud2l0aF9sb2dfZGlyKCJsb2dzIikKICAgICAgICAud2l0aF9yb290X2RpcigmY29uZmlnLndvcmtkaXIpOw==", "target": "/Users/tony/programming/castep_workflow_framework/examples/hubbard_u_sweep_slurm/src/main.rs", "index": 4, "is_create": false}]')

for step in STEPS:
    before = base64.b64decode(step["before_b64"]).decode()
    after = base64.b64decode(step["after_b64"]).decode()
    target = step["target"]
    idx = step["index"]
    is_create = step["is_create"]

    if is_create:
        target_path = Path(target)
        target_path.parent.mkdir(parents=True, exist_ok=True)
        target_path.write_text(after)
        print(f"OK {TASK_ID} change {idx}: created {target}")
    else:
        target_path = Path(target)
        content = target_path.read_text()
        if before not in content:
            print(f"FAILED {TASK_ID} change {idx}: pattern not found in {target}", file=sys.stderr)
            print(f"Expected (first 200 chars): {repr(before[:200])}", file=sys.stderr)
            sys.exit(1)

        result = subprocess.run(
            ["sd", "-F", "-A", "-n", "1", "--", before, after, target],
            capture_output=True, text=True,
        )
        if result.returncode != 0:
            print(f"FAILED {TASK_ID} change {idx}: sd error: {result.stderr}", file=sys.stderr)
            sys.exit(result.returncode)

        new_content = target_path.read_text()
        if after and after not in new_content:
            print(f"FAILED {TASK_ID} change {idx}: replacement not found after apply", file=sys.stderr)
            sys.exit(1)

        print(f"OK {TASK_ID} change {idx}: applied to {target}")

print(f"OK {TASK_ID}: all changes applied")
